class ElasticsearchLogHandler(logging.Handler):
    """Custom logging handler that sends logs to Elasticsearch."""

    def __init__(self, es_client: Elasticsearch, index_prefix: str = "app-logs"):
        super().__init__()
        self.es_client = es_client
        self.index_prefix = index_prefix
        self.buffer = []
        self.buffer_size = 50

    def _get_index_name(self) -> str:
        return f"{self.index_prefix}-{datetime.utcnow().strftime('%Y.%m.%d')}"

    def emit(self, record: logging.LogRecord):
        try:
            log_entry = {
                "timestamp": datetime.utcnow().isoformat(),
                "level": record.levelname,
                "logger_name": record.name,
                "message": self.format(record),
                "module": record.module,
                "function": record.funcName,
                "line_number": record.lineno,
                "process_id": record.process,
                "thread_name": record.threadName,
            }

            if record.exc_info and record.exc_info[0] is not None:
                log_entry["exception"] = self.formatException(record.exc_info)

            self.buffer.append({
                "_index": self._get_index_name(),
                "_source": log_entry
            })

            if len(self.buffer) >= self.buffer_size:
                self.flush()

        except Exception as e:
            print(f"Failed to emit log record to Elasticsearch: {e}")

    def flush(self):
        if self.buffer:
            try:
                helpers.bulk(self.es_client, self.buffer, raise_on_error=False)
                self.buffer = []
            except Exception as e:
                print(f"Failed to flush logs to Elasticsearch: {e}")

    def close(self):
        self.flush()
        super().close()


