    def search_logs(self, query: str = None, level: str = None,
                     service: str = None, time_from: str = None,
                     time_to: str = None, size: int = 100,
                     index_pattern: str = "app-logs-*") -> dict:
        """Search logs with various filters."""
        must = []
        filter_ = []

        if query:
            must.append({
                "multi_match": {
                    "query": query,
                    "fields": ["message", "exception", "logger_name"],
                    "type": "best_fields"
                }
            })

        if level:
            filter_.append({"term": {"level": level.upper()}})

        if service:
            filter_.append({"term": {"service": service}})

        time_range = {}
        if time_from:
            time_range["gte"] = time_from
        if time_to:
            time_range["lte"] = time_to
        if time_range:
            filter_.append({"range": {"timestamp": time_range}})

        if not must:
            must.append({"match_all": {}})

        body = {
            "query": {
                "bool": {
                    "must": must,
                    "filter": filter_
                }
            },
            "size": size,
            "sort": [{"timestamp": {"order": "desc"}}],
            "track_total_hits": True
        }

        try:
            result = self.es.search(index=index_pattern, body=body)
            return self._format_search_results(result)
        except Exception as e:
            logger.error(f"Log search failed: {e}")
            raise

