    # ==================== Utility Methods ====================

    def _format_search_results(self, result: dict) -> dict:
        """Format Elasticsearch search results into a cleaner structure."""
        hits = []
        for hit in result["hits"]["hits"]:
            formatted_hit = {
                "id": hit["_id"],
                "index": hit["_index"],
                "score": hit["_score"],
                "source": hit["_source"]
            }
            if "highlight" in hit:
                formatted_hit["highlight"] = hit["highlight"]
            hits.append(formatted_hit)

        return {
            "total": result["hits"]["total"]["value"],
            "max_score": result["hits"].get("max_score"),
            "hits": hits,
            "took_ms": result["took"]
        }

    def get_cluster_health(self) -> dict:
        """Get Elasticsearch cluster health status."""
        return self.es.cluster.health()

    def get_index_stats(self, index_name: str) -> dict:
        """Get statistics for a specific index."""
        try:
            stats = self.es.indices.stats(index=index_name)
            index_stats = stats["indices"][index_name]
            return {
                "doc_count": index_stats["primaries"]["docs"]["count"],
                "size_bytes": index_stats["primaries"]["store"]["size_in_bytes"],
                "search_count": index_stats["primaries"]["search"]["query_total"],
                "index_count": index_stats["primaries"]["indexing"]["index_total"]
            }
        except Exception as e:
            logger.error(f"Failed to get index stats: {e}")
            raise

    def cleanup_old_indices(self, index_prefix: str = "app-logs",
                             days_to_keep: int = 30) -> list[str]:
        """Delete log indices older than specified days."""
        cutoff_date = datetime.utcnow() - timedelta(days=days_to_keep)
        deleted_indices = []

        try:
            indices = self.es.indices.get(index=f"{index_prefix}-*")
            for index_name in indices:
                try:
                    date_str = index_name.replace(f"{index_prefix}-", "")
                    index_date = datetime.strptime(date_str, "%Y.%m.%d")
                    if index_date < cutoff_date:
                        self.delete_index(index_name)
                        deleted_indices.append(index_name)
                except ValueError:
                    continue

            logger.info(f"Cleaned up {len(deleted_indices)} old indices.")
            return deleted_indices
        except Exception as e:
            logger.error(f"Index cleanup failed: {e}")
            raise

    def setup_log_handler(self, logger_instance: logging.Logger = None,
                           index_prefix: str = "app-logs",
                           level: int = logging.INFO):
        """Attach Elasticsearch log handler to a logger."""
        handler = ElasticsearchLogHandler(self.es, index_prefix=index_prefix)
        handler.setLevel(level)
        formatter = logging.Formatter(
            '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
        )
        handler.setFormatter(formatter)

        target_logger = logger_instance or logging.getLogger()
        target_logger.addHandler(handler)
        return handler


