    es_manager.create_log_index_template()

    # Create document search index
    print("\n=== Creating document index ===")
    es_manager.create_document_index("documents")

    # Index sample documents
    print("\n=== Indexing sample documents ===")
    sample_documents = [
        {
            "title": "Introduction to Elasticsearch",
            "content": "Elasticsearch is a distributed, RESTful search and analytics engine. "
                       "It is built on top of Apache Lucene and provides a powerful full-text "
                       "search capability with near real-time performance.",
            "author": "John Doe",
            "tags": ["elasticsearch", "search", "tutorial"],
            "category": "Technology",
            "created_at": datetime.utcnow().isoformat(),
            "views": 1500,
            "rating": 4.8
        },
        {
            "title": "Python Logging Best Practices",
            "content": "Effective logging is crucial for debugging and monitoring applications. "
                       "Python's logging module provides a flexible framework for emitting log "
                       "messages from Python programs. Using structured logging with Elasticsearch "
                       "enables powerful log analysis.",
            "author": "Jane Smith",
            "tags": ["python", "logging", "best-practices"],
            "category": "Programming",
            "created_at": datetime.utcnow().isoformat(),
            "views": 2300,
            "rating": 4.5
        },
        {
            "title": "Building a Centralized Logging Platform",
            "content": "A centralized logging platform aggregates logs from multiple services "
                       "and provides a unified search interface. Elasticsearch combined with "
                       "Kibana offers an excellent solution for log aggregation and visualization.",
            "author": "Bob Wilson",
            "tags": ["logging", "elasticsearch", "devops", "monitoring"],
            "category": "DevOps",
            "created_at": datetime.utcnow().isoformat(),
            "views": 890,
            "rating": 4.2
        },
        {
            "title": "Microservices Architecture and Observability",
            "content": "In a microservices architecture, observability is key to understanding "
                       "system behavior. This includes logging, metrics, and distributed tracing. "
                       "Centralized logging with Elasticsearch helps correlate events across services.",
            "author": "Alice Brown",
            "tags": ["microservices", "observability", "architecture"],
            "category": "Architecture",
            "created_at": datetime.utcnow().isoformat(),
            "views": 3100,
            "rating": 4.9
        },
        {
            "title": "Full-Text Search Techniques",
            "content": "Full-text search allows users to search through large volumes of text "
                       "data efficiently. Techniques include tokenization, stemming, and relevance "
                       "scoring using TF-IDF or BM25 algorithms.",
            "author": "John Doe",
            "tags": ["search", "algorithms", "information-retrieval"],
            "category": "Technology",
            "created_at": datetime.utcnow().isoformat(),
            "views": 1700,
            "rating": 4.6
        }
    ]

    result = es_manager.bulk_index_documents("documents", sample_documents)
    print(f"Bulk index result: {result['success']} documents indexed")

    # Wait for indexing to complete
    es_manager.es.indices.refresh(index="documents")

    # Full-text search
    print("\n=== Full-Text Search: 'elasticsearch logging' ===")
    search_results = es_manager.full_text_search(
        "documents", "elasticsearch logging",
        fields=["title^3", "content", "tags^2"]
    )
    print(f"Found {search_results['total']} results (took {search_results['took_ms']}ms):")
    for hit in search_results["hits"]:
        print(f"  - [{hit['score']:.2f}] {hit['source']['title']}")
        if "highlight" in hit:
            for field, fragments in hit["highlight"].items():
                print(f"    {field}: {fragments[0]}")

    # Phrase search
    print("\n=== Phrase Search: 'centralized logging platform' ===")
    phrase_results = es_manager.phrase_search(
        "documents", "content", "centralized logging platform", slop=2
    )
    print(f"Found {phrase_results['total']} results:")
    for hit in phrase_results["hits"]:
        print(f"  - {hit['source']['title']}")

    # Advanced search with filters
    print("\n=== Advanced Search: Technology category, rating > 4.5 ===")
    advanced_results = es_manager.advanced_search(
        "documents",
        must=[{"match": {"content": "search"}}],
        filter_=[
            {"term": {"category": "Technology"}},
            {"range": {"rating": {"gt": 4.5}}}
        ],
        sort=[{"rating": {"order": "desc"}}]
    )
    print(f"Found {advanced_results['total']} results:")
    for hit in advanced_results["hits"]:
        print(f"  - {hit['source']['title']} (rating: {hit['source']['rating']})")

    # Aggregation search
    print("\n=== Aggregations: Category and Author Distribution ===")
    agg_results = es_manager.search_with_aggregations(
        "documents",
        aggregations={
            "categories": {
                "terms": {"field": "category", "size": 10}
            },
            "authors": {
                "terms": {"field": "author", "size": 10}
            },
            "avg_rating": {
                "avg": {"field": "rating"}
            },
            "total_views": {
                "sum": {"field": "views"}
            },
            "rating_ranges": {
                "range": {
                    "field": "rating",
                    "ranges": [
                        {"to": 4.0, "key": "below_4"},
                        {"from": 4.0, "to": 4.5, "key": "4_to_4.5"},
                        {"from": 4.5, "key": "above_4.5"}
                    ]
                }
            }
        }
    )
    print(f"Total documents: {agg_results['total_hits']}")
    print(f"Average rating: {agg_results['aggregations']['avg_rating']['value']:.2f}")
    print(f"Total views: {int(agg_results['aggregations']['total_views']['value'])}")
    print("Categories:")
    for bucket in agg_results["aggregations"]["categories"]["buckets"]:
        print(f"  - {bucket['key']}: {bucket['doc_count']}")
    print("Authors:")
    for bucket in agg_results["aggregations"]["authors"]["buckets"]:
        print(f"  - {bucket['key']}: {bucket['doc_count']}")

    # Index sample log entries
    print("\n=== Indexing Sample Log Entries ===")
    sample_logs = [
        {
            "timestamp": (datetime.utcnow() - timedelta(hours=i)).isoformat(),
            "level": level,
            "logger_name": f"service.{module}",
            "message": message,
            "module": module,
            "function": "handler",
            "line_number": 42 + i,
            "process_id": 1234,
            "thread_name": "MainThread",
            "service": service,
            "environment": "production",
            "host": f"server-{(i % 3) + 1}",
            "metadata": {"duration_ms": duration, "request_id": f"req-{i:04d}"}
        }
        for i, (level, module, message, service, duration) in enumerate([
            ("INFO", "api", "Request processed successfully", "user-service", 150),
            ("WARNING", "db", "Slow query detected on users table", "user-service", 2500),
            ("ERROR", "api", "Connection timeout to payment gateway", "payment-service", 5000),
            ("INFO", "auth", "User authentication successful", "auth-service", 85),
            ("ERROR", "api", "Internal server error in order processing", "order-service", 3200),
            ("INFO", "api", "Health check passed", "user-service", 12),
            ("CRITICAL", "db", "Database connection pool exhausted", "order-service", 10000),
            ("WARNING", "cache", "Cache miss rate above threshold", "product-service", 450),
            ("INFO", "api", "Request processed successfully", "product-service", 200),
            ("ERROR", "api", "Connection timeout to payment gateway", "payment-service", 5100),
            ("INFO", "scheduler", "Batch job completed", "batch-service", 45000),
            ("WARNING", "api", "Rate limit approaching for client xyz", "api-gateway", 30),
        ])
    ]

    es_manager.bulk_index_logs(sample_logs)

    # Refresh log indices
    es_manager.es.indices.refresh(index="app-logs-*")

    # Search logs
    print("\n=== Log Search: 'timeout' ===")
    log_results = es_manager.search_logs(query="timeout")
    print(f"Found {log_results['total']} log entries:")
    for hit in log_results["hits"]:
        src = hit["source"]
        print(f"  [{src['level']}] {src['service']}: {src['message']}")

    # Search logs by level
    print("\n=== Log Search: ERROR level ===")
    error_logs = es_manager.search_logs(level="ERROR")
    print(f"Found {error_logs['total']} error log entries:")
    for hit in error_logs["hits"]:
        src = hit["source"]
        print(f"  [{src['timestamp']}] {src['service']}: {src['message']}")

    # Log level distribution
    print("\n=== Log Level Distribution ===")
    distribution = es_manager.get_log_level_distribution()
    print(f"Total log entries: {distribution['total_hits']}")
    if "log_levels" in distribution["aggregations"]:
        for bucket in distribution["aggregations"]["log_levels"]["buckets"]:
            print(f"  {bucket['key']}: {bucket['doc_count']}")

    # Error summary
    print("\n=== Error Summary (Last 24 hours) ===")
    error_summary = es_manager.get_error_summary(hours=24)
    print(f"Total errors: {error_summary['total_hits']}")
    if "errors_by_service" in error_summary["aggregations"]:
        print("Errors by service:")
        for bucket in error_summary["aggregations"]["errors_by_service"]["buckets"]:
            print(f"  {bucket['key']}: {bucket['doc_count']}")

    # Service stats
    print("\n=== Service Statistics ===")
    service_stats = es_manager.get_service_stats()
    if "services" in service_stats["aggregations"]:
        for bucket in service_stats["aggregations"]["services"]["buckets"]:
            print(f"\n  Service: {bucket['key']} ({bucket['doc_count']} logs)")
            if "log_levels" in bucket:
                for level_bucket in bucket["log_levels"]["buckets"]:
                    print(f"    {level_bucket['key']}: {level_bucket['doc_count']}")

    # Slow operations
    print("\n=== Slow Operations (>1000ms) ===")
    try:
        slow_ops = es_manager.get_slow_operations(threshold_ms=1000, hours=24)
        print(f"Total slow operations: {slow_ops['total_slow_operations']}")
        if slow_ops.get("aggregations"):
            aggs = slow_ops["aggregations"]
            if "avg_duration" in aggs:
                print(f"Average duration: {aggs['avg_duration']['value']:.0f}ms")
            if "max_duration" in aggs:
                print(f"Max duration: {aggs['max_duration']['value']:.0f}ms")
        for op in slow_ops["operations"][:5]:
            print(
                f"  [{op['level']}] {op['service']}: {op['message']} "
                f"({op['metadata']['duration_ms']}ms)"
            )
    except Exception as e:
        print(f"  Could not retrieve slow operations: {e}")

    # Set up Elasticsearch log handler for Python logging
    print("\n=== Setting up Elasticsearch Log Handler ===")
    app_logger = logging.getLogger("myapp")
    es_handler = es_manager.setup_log_handler(app_logger, level=logging.DEBUG)

    # Generate some application logs that will be sent to Elasticsearch
    app_logger.info("Application started successfully")
    app_logger.warning("Configuration file not found, using defaults")
    app_logger.error("Failed to connect to external API")

    # Flush the handler to ensure logs are sent
    es_handler.flush()
    print("Application logs sent to Elasticsearch.")

    # Get index stats
    print("\n=== Index Statistics ===")
    try:
        doc_stats = es_manager.get_index_stats("documents")
        print(f"Documents index: {doc_stats['doc_count']} docs, "
              f"{doc_stats['size_bytes']} bytes")
    except Exception as e:
        print(f"  Could not get stats: {e}")

    # Clean up demo indices (optional)
    print("\n=== Cleanup ===")
    es_manager.delete_index("documents")
    print("Demo complete!")


